	socketStatus: -1,

	/** TRUE if websocket connection is open. And FALSE when it closes
	 * @type {boolean}
	 */
	isSocketOpen: false, // if we stop receiving heartbeat from server, we set this to false after setTimeout

	/** TRUE if and only after a response is received. FALSE untill then
	 * @type {boolean}
	 */
	isSocketResponding: false,

	/** @type {boolean} Toggles between FALSE and TRUE upon receiving tick data from WebSocket. Preferred instead of a counter */
	tick: false,

	/**	Quotes for subscribed instruments updated by WebSocket for NSE exchange
	 * @type {Object.<string, {ltp:number,cp:number }>}
	 */
