	/**
	 * Subscribes to quotes (if not already)
	 * @param {string[]} instrumentTokenAry - An array of instrument tokens
	 * @returns {Promise<boolean>}
	 */
	subscribeToQuotes: (instrumentTokenAry) => {}, //eslint-disable-line

	/**
	 * Unsubscribes the given instruments from websocket quotes
	 * @param {string[]} instrumentTokenAry - An array of instrument tokens
	 * @returns {Boolean} TRUE in case request to unsubscribe sent successfully. FALSE otherwise
	 */
