	const __doOnWebSocketResponse = (respData) => {
		try {
			//copy ws response as hex using chrome and paste in -- https://hexed.it/
			//console.log(`WS resp type: ${respData.constructor.name}`);
			//console.log(JSON.parse(respData));
			if (respData.constructor.name != 'Blob') return; //few msgs would be in 'String' type which we can parse as JSON
			//console.log('Size in bytes:',respData.size);
			// const totalBytes = respData.size;
			if (respData.size <= 1) return; //we ignore the 1-byte heartbeat sent by server to keep connection alive	//or maybe use that to set a flag to tell us that con is alive
			respData.arrayBuffer().then((aryBufr) => {
				// const chunk = new Int32Array(aryBufr);	//new Int16Array(buffer, byteOffset, length)
				// console.log('Num packets:',chunk);
				//console.log('ArrayBuffer size:',aryBufr.byteLength,'bytes');
				const totalBytes = aryBufr.byteLength;
				if (totalBytes <= 2) return; //no need here, since we already check for skipping heartbeat above
				const view = new DataView(aryBufr); //ArrayBuffer, byte-offset!, byte-length!

				//--------------------------------------+
				//	TRIAL READING OF FIRST INSTRUMENT	|
				//--------------------------------------+
				// //const nextBytes = view.getUint8(1);	//read the 2nd byte (at offset 1)	//seemingly tells us about how many bytes next constitute the instrument data
				// //const strLength = view.getUint8(3);	//read the 4th byte (at offset 3)	//seemingly tells about the number of next text bytes
				// let textBytes = new Uint8Array(aryBufr, 4, 19); //19 bytes starting from offset 4
				// let token = String.fromCharCode.apply(null, textBytes).trim(); //replace(/\0/g, ''); // Remove null delimiters
				// let ltp = Number(view.getFloat64(28, true)); //jump to reading LTP //we convert it to number before performing arithmatic ops using it
				// let closePrice = Number(view.getFloat64(46, true)); //jump to reading close-price
				// console.log('WS quote token:', token, ' | ltp: ', ltp, ' | cp:', closePrice);
				// quotesBasket.current[token] = { ltp: ltp, cp: closePrice };

				// const numInstruments = Math.floor(totalBytes / 54); //since each instrument occupies 54 bytes
				// let seekOffset = 0;
				// for (var i = 0; i < numInstruments; i++) {
				// 	seekOffset += 4;
				// 	let textBytes = new Uint8Array(aryBufr, seekOffset, 19); //19 bytes starting from seekOffset
				// 	let token = String.fromCharCode.apply(null, textBytes); //.trim(); //replace(/\0/g, ''); // Remove null delimiters
				// 	seekOffset += 24; //19 (from above reading op) + 5
				// 	let ltp = Number(view.getFloat64(seekOffset, true)); //jump to reading LTP //we convert it to number before performing arithmatic ops using it
				// 	seekOffset += 18; //8 (from above reading op) + 10
				// 	let closePrice = Number(view.getFloat64(seekOffset, true)); //jump to reading close-price
				// 	seekOffset += 8; //8 (from above reading op)	//in prep for next loop iteration
				// 	// console.log('WS quote token:', token, ' | ltp: ', ltp, ' | cp:', closePrice);
				// 	quotesBasket.current[token] = { ltp: ltp, cp: closePrice };
				// }

				let seekOffset = 0;
				if (view.getUint8(0) === 8 && view.getUint8(1) === 1) seekOffset = 2;
				//the first 2 bytes are not present in the first incoming msg after we send() a msg.
				//These are present in the tick updates. We read the bytes and skip to offset accordingly
				while (seekOffset < totalBytes) {
					seekOffset += 1; //skip first byte
					const dataNumBytesNext = view.getUint8(seekOffset); //read the 2nd byte (at offset 1)	//tells us about how many bytes next constitute the instrument data
					seekOffset += 1; //advance 1 byte forward
					const dataEndsAtByte = seekOffset + dataNumBytesNext;
					if (dataEndsAtByte > totalBytes) break; //break out of loop if it overflows / goes out of bounds
					seekOffset += 1; //also skip third byte
					const strLength = view.getUint8(seekOffset); //read the 4th byte (at offset 3)	//tells about the number of next text bytes
					seekOffset += 1; //advance 1 byte forward
					let textBytes = new Uint8Array(aryBufr, seekOffset, strLength); //'strLength' num of bytes starting from seekOffset
					let token = String.fromCharCode.apply(null, textBytes);
					seekOffset += strLength; //advance 'strLength' num of bytes forward
					seekOffset += 5; //skip next 5 bytes
					let ltp = Number(view.getFloat64(seekOffset, true)); //we convert it to number before performing arithmatic ops using it
					// seekOffset += 8; //advance 8 bytes forward
					seekOffset = dataEndsAtByte - 8; //jump to reading the last 8 bytes
					let closePrice = Number(view.getFloat64(seekOffset, true)); //read close-price
					seekOffset += 8; //advance 8 bytes forward, in prep for next loop iteration

					if (seekOffset > totalBytes) break; //break out of loop if it overflows / goes out of bounds
					// console.log('WS quote token:', token, ' | ltp: ', ltp, ' | cp:', closePrice);
					quotesBasket.current[token] = { ltp: ltp, cp: closePrice };
				}

				// console.log('UpstoxWebSocket with newly appended quotes:', Object.keys(quotesBasket.current));
				//optionally here broadcast via channel to other tabs

				// setTick(tick + 1);
				// setTick((tk) => tk + 1); // setTick(tick + 1, () => console.log('tick after setting state :', tick));
				setTick((tk) => !tk); //this is only to trigger state change in child components / consumers
			});
		} catch (err) {
			// console.error(err);
			return;
		}
	};

	/** Generates a random GUID (to be used in JSON data sent via websocket send() method) */
	const generateGUID = () => {
		return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
			var r = (Math.random() * 16) | 0,
				v = c === 'x' ? r : (r & 0x3) | 0x8;
			return v.toString(16);
		});
	};

	/** Converts string to ArrayBuffer (may be required format by Upstox ws send() fn)
	 * @see https://developer.chrome.com/blog/how-to-convert-arraybuffer-to-and-from-string
	 */
	const _str2ab = (str) => {
		// Foll 2 lines are for NODE-JS using the 'buffer' package/module
		// const { Buffer } = require('node:buffer');
		// const buf = Buffer.from('hello world', 'utf8');

		//javascript implementation
		var buf = new ArrayBuffer(str.length);
		var bufView = new Uint8Array(buf);
		for (var i = 0, strLen = str.length; i < strLen; i++) {
			bufView[i] = str.charCodeAt(i);
		}
		return buf;
	};

	const _sendMsgAndRetryIfNoResponse = (msgToSend) => {
		if (!msgToSend || msgToSend == undefined) return false;
		try {
			webSocketRef.current?.send(msgToSend);
			//here set retry timer wich shall be unset upon receiving response
			//the retry timer will be be set to re-execute this very fn with the same arguments after a specified time
			retryTimeoutRef.current !== null && clearTimeout(retryTimeoutRef.current);
			retryTimeoutRef.current = setTimeout(() => {
				// closeSocketConnection(); //close unresponsive connection	//this is already handled for us inside below fn '_createSocketConnection()'
				_createSocketConnection() //create a new connection & retry
					.then((socket) => {
						if (!socket) throw new Error();
						// socket.send(msgToSend);	//this won't fire subsequent retrials if this retry fails too
						//by this time, 'webSocketRef.current' should already be pointing to the newly created websocket handle
						_sendMsgAndRetryIfNoResponse(msgToSend);
					})
					.catch((err) => {
						console.error(err.message || 'Error creating auxilary socket connection');
					});
			}, 9000); //keep retrying every 9 seconds until a response is received which shall clear the timeout
			console.log('WS: Retry timer set');
			// console.log(retryTimeoutRef.current, typeof retryTimeoutRef.current);	//value of retryTimeoutRef.current shall be any 'number', ie the timeoutId
			return true;
		} catch (err) {
			// console.log(err.message || 'Error sending data over socket');
			return false;
		}
	};

