// /** React component to display Angel One marketwatch list and search results
//  * @param {Object} props Props passed to this component
//  * @param {?()=>{}} [props.openNewOrAddToPosition=()=>{}] Callback fn passed down by the positions component. We pass this callbck fn to the new-position dialog component in order for it to add to position
