/** React component to display Upstox marketwatch list and search results
 * @param {Object} props Props passed to this component
 * @param {?()=>{}} [props.openNewOrAddToPosition=()=>{}] Callback fn passed down by the positions component. We pass this callbck fn to the new-position dialog component in order for it to tell positions component to refresh itself
 * @param {?()=>{}} [props.setBottomSheetTitle=()=>{}] Sets the bottom-sheet title
 * @param {?()=>{}} [props.setBottomSheetDesc=()=>{}] Sets the bottom-sheet description
 * @param {?()=>{}} [props.closeBottomSheet=()=>{}] When displayed inside bottomsheet, we use it to close sheet once trade is successfully entered
 * @param {()=>{}} props.readInstrumentTokensOfActivePositions Returns an array of instrument tokens of active positions. Useful to avoid these instruments when unsubscribing from ws for watchlist instruments
 */
export default function UpstoxMarketWatch({
	openNewOrAddToPosition,
	setBottomSheetTitle,
	setBottomSheetDesc,
	closeBottomSheet,
	readInstrumentTokensOfActivePositions,
}) {
	const [isReady, setIsReady] = useState(false); //we shall set this to true once we receive the first quote tick from WS
	const [activeWatchlistIndex, setActiveWatchlistIndex] = useState(0); //index of active watchlist (Kaagzi provides 4 watchlists)
	const [watchlistInstrumentsAry, setWatchlistInstrumentsAry] = useState(/** @type {Instrument[]} */ ([]));
	const [watchlistInstrumentsNotFoundAry, setWatchlistInstrumentsNotFoundAry] = useState(
		/** @type {{symbol:string,exchange:('NSE'|'BSE'|'NFO'|'MCX'|'CDS')}[]} */ ([]),
	);
	const [currentlyExpandedInstrument, setCurrentlyExpandedInstrument] = useState(/** @type {Instrument} */ ({}));
	const [instrumentInvokedForTransaction, setInstrumentInvokedForTransaction] = useState(/** @type {Instrument} */ ({}));
	const [searchQuery, setSearchQuery] = useState('');

	const { notify } = useContext(ToastNotificationContext);
	const isOnline = useContext(NetworkCheckContext);
	const { checkIfPlanActive } = useContext(UserContext);
	const { isMasterDataReady, getInstruments } = useContext(UpstoxMasterDataContext);
	const { getWatchlistInstruments, setWatchlistMultipleInstruments, deleteWatchlistInstrument } = useContext(AppDataIndexedDbContext);
	const { socketStatus, quotes, tick, subscribeToQuotes, unsubscribeToQuotes } = useContext(UpstoxWebSocketContext);
	const maxNumInstrumentsPerWatchlist = 10;

	/** Only unsubscribes instrument tokens for which no open position exists
	 * @param {string[]} instrumentTokenAry Array of instrument tokens of watchlist instruments we wish to unsubscribe from ws live quotes
	 * @returns {?string[]} Array of instrument tokens (for which no position is open) successfully unsubscribed OR null
	 */
	const _unsubscribeToQuotes_nonPositionTokensOnly = (instrumentTokenAry) => {
		if (!isOnline) return null;
		try {
			/** @type {string[]} */
			const instrumentTokensOfActivePositions_ary = readInstrumentTokensOfActivePositions();
			const filteredInstrumentTokenAry = instrumentTokenAry.filter((token) => !instrumentTokensOfActivePositions_ary.includes(token));
			if (filteredInstrumentTokenAry.length < 1) return null;
			unsubscribeToQuotes(filteredInstrumentTokenAry);
			return filteredInstrumentTokenAry;
		} catch (err) {
			return null;
		}
	};

	const getWatchlist_n_loadIntoState_n_subscribeToWsLiveQuotes = async () => {
		try {
			// const isPlanActive =
			await checkIfPlanActive(); //this shall cause the 'PlanExpiryGateway' component to not render this component and display plan expired dialog
			// if (!isPlanActive) throw new Error('Plan Expired!');
			//here we first read the generic broker-agnostic watchlist instruments stored in Kaagzi DB
			const kaagziWatchlistInstrumentsAry = await getWatchlistInstruments(activeWatchlistIndex + 1);
			if (!kaagziWatchlistInstrumentsAry || !kaagziWatchlistInstrumentsAry?.length) throw new Error('No instruments listed in watchlist');

			//then resolve instrument_token (for use in WS live ticks) for each position by reading from AngelOne Master-Data DB
			const mappedObj = kaagziWatchlistInstrumentsAry.reduce((acc, item) => {
				// If the exchange key doesn't exist, create it with an empty array
				if (!acc[item.xh]) {
					acc[item.xh] = [];
				}
				// Push the current symbol onto the array for this exchange
				acc[item.xh].push(item.sbl);
				return acc;
			}, {});

			const instrumentsFoundNotFoundObj = await getInstruments(mappedObj);
			if (!instrumentsFoundNotFoundObj) {
				setIsReady(true); //since we need not have to wait for quote tick from websocket
				throw new Error('Error resolving instruments with Upstox');
			}

			//IF BOTH, 'INSTRUMENTS-FOUND' AND 'INSTRUMENTS-NOT-FOUND' DO NOT EXIST
			if (
				(!Object.prototype.hasOwnProperty.call(instrumentsFoundNotFoundObj, 'instrumentsFound') ||
					instrumentsFoundNotFoundObj.instrumentsFound.length < 1) &&
				(!Object.prototype.hasOwnProperty.call(instrumentsFoundNotFoundObj, 'instrumentsNotFound') ||
					instrumentsFoundNotFoundObj.instrumentsNotFound.length < 1)
			) {
				setIsReady(true); //since we need not have to wait for quote tick from websocket
				throw new Error('No Instruments found for watchlist-' + (activeWatchlistIndex + 1));
			}

			//IF 'INSTRUMENTS-NOT-FOUND' EXIST
			if (
				Object.prototype.hasOwnProperty.call(instrumentsFoundNotFoundObj, 'instrumentsNotFound') &&
				instrumentsFoundNotFoundObj.instrumentsNotFound.length > 0
			) {
				//list these instruments which were not found so as to allow user to delete them or delete them without asking
				setWatchlistInstrumentsNotFoundAry(instrumentsFoundNotFoundObj.instrumentsNotFound);
				notify(instrumentsFoundNotFoundObj.instrumentsNotFound.length + ' instruments not loaded!', 'err');
			}

			//here we unsubscribe old list
			isOnline && watchlistInstrumentsAry.length > 0 && _unsubscribeToQuotes_nonPositionTokensOnly(watchlistInstrumentsAry.map(({ token }) => token));

			//IF 'INSTRUMENTS-FOUND' EXIST
			if (
				Object.prototype.hasOwnProperty.call(instrumentsFoundNotFoundObj, 'instrumentsFound') &&
				instrumentsFoundNotFoundObj.instrumentsFound.length > 0
			) {
				setWatchlistInstrumentsAry(instrumentsFoundNotFoundObj.instrumentsFound);
				//here subscribe to newly fetched instruments from this watchlist we just switched to
				//isOnline && (await subscribeToQuotes(instrumentsFoundNotFoundObj.instrumentsFound.map(({ instrument_token }) => Number(instrument_token))));
				isOnline && (await subscribeToQuotes(instrumentsFoundNotFoundObj.instrumentsFound.map(({ token }) => token)));
			} else {
				//IF 'INSTRUMENTS-FOUND' DO NOT EXIST
				setIsReady(true); //since we need not have to wait for quote tick from websocket
			}
		} catch (err) {
			isOnline && watchlistInstrumentsAry.length > 0 && _unsubscribeToQuotes_nonPositionTokensOnly(watchlistInstrumentsAry.map(({ token }) => token));
			setWatchlistInstrumentsAry([]);
			setIsReady(true); //since we need not have to wait for quote tick from websocket
			return null;
		}
	};

	// /**
	//  * Add instruments to the watchlist
	//  * @param {{'instrument_token':Instrument,'another_instrument_token':Instrument}} instrumentsObj Instruments to add listed in an object with instrument_token as the key
	//  * @returns {Promise<boolean>} TRUE in case instruments added successfully, FALSE otherwise
	//  */
	// const addInstruments = async (instrumentsObj) => {
	//		if (!instrumentsObj || typeof instrumentsObj !== 'object') return false;
	//		const tokensAry = Object.keys(instrumentsObj);
	//		if (tokensAry.length < 1) return false;
	//		const instrumentsToBeAddedAry = tokensAry.map((token) => instrumentsObj[token]);
	//}

	/**
	 * Add multiple instruments to the watchlist
	 * @param {Instrument[]} instrumentsToBeAddedAry Array of instrument objects to be added
	 * @returns {Promise<boolean>} TRUE in case instruments added successfully, FALSE otherwise
	 */
	const addInstruments = async (instrumentsToBeAddedAry) => {
		if (!instrumentsToBeAddedAry || !Array.isArray(instrumentsToBeAddedAry) || instrumentsToBeAddedAry.length < 1) return false;

		//here maybe check limit for max number of allowed instruments for the currently active watchlist
		const availableSpots = maxNumInstrumentsPerWatchlist - watchlistInstrumentsAry.length;
		if (instrumentsToBeAddedAry.length > availableSpots) {
			notify('Only ' + availableSpots + ' more instruments can be added to watchlist-' + (activeWatchlistIndex + 1));
			return false;
		}
		try {
			const isPlanActive = await checkIfPlanActive(); //this shall cause the 'PlanExpiryGateway' component to not render this component and display plan expired dialog
			if (!isPlanActive) throw new Error('Plan Expired!');
			//Loop over items in the array and convert Angel One Instrument object to Kaagzi instrument object
			// const kiteToKaagziInstrumentFormatAry = instrumentsToBeAddedAry.map((instrumentToBeAdded) => ({
			// 	sbl: instrumentToBeAdded.symbol,
			// 	xh: instrumentToBeAdded.segment,
			// 	x: instrumentToBeAdded.expiry,
			// }));
			const kiteToKaagziInstrumentFormatAry = instrumentsToBeAddedAry.map((instrumentToBeAdded) => {
				const kaagziWatchlistInstrumentObj = { sbl: instrumentToBeAdded.symbol, xh: instrumentToBeAdded.segment };

				//parse expiry
				if (
					Object.prototype.hasOwnProperty.call(instrumentToBeAdded, 'expiry') &&
					instrumentToBeAdded.expiry &&
					instrumentToBeAdded.expiry.toString().trim() !== ''
				) {
					kaagziWatchlistInstrumentObj.x = instrumentToBeAdded.expiry; //new Date(instrumentToBeAdded.expiry).getTime(); //new Date('04JUL2024').getTime();
				}
				return kaagziWatchlistInstrumentObj;
			});

			const writeOpStatus = await setWatchlistMultipleInstruments(activeWatchlistIndex + 1, kiteToKaagziInstrumentFormatAry);
			if (!writeOpStatus) throw new Error('Failed to add instruments to watchlist');

			////// AFTER ADDING TO DB, ADD TO STATE TOO

			//here add to state //only if it doesn't already exist
			const watchlistInstrumentsAryCopy = [...watchlistInstrumentsAry]; // Create a new array to hold the new state by cloning the previous
			// Iterate over each of the instruments to be added and compare with items instruments already present in watchlist
			for (const instrumentToBeAdded of instrumentsToBeAddedAry) {
				// Check if the instrument already exists in the watchlist
				const exists = watchlistInstrumentsAryCopy.some(
					//we could just as well have iterated over 'watchlistInstrumentsAry' instead of 'watchlistInstrumentsAryCopy' since both are copies of each other
					(existingInstrument) =>
						// existingInstrument.tradingsymbol === instrumentToBeAdded.tradingsymbol && existingInstrument.exchange === instrumentToBeAdded.exchange,
						existingInstrument.token === instrumentToBeAdded.token, //comparing instrument token should be enough
				);
				if (!exists) watchlistInstrumentsAryCopy.push(instrumentToBeAdded); // If the instrument does not exist, add it to the new state array
			}
			setWatchlistInstrumentsAry(watchlistInstrumentsAryCopy); // Update the state with the new array

			//here subscribe to WS live quotes //or perhaps this may not be necessary since we would be transitioning back to wathlists from search page
			// isOnline && (await subscribeToQuotes(_segregateInstrumentTokenByExchanges(watchlistInstrumentsAryCopy)));
			isOnline && (await subscribeToQuotes(watchlistInstrumentsAryCopy.map(({ token }) => token)));
			return true;
		} catch (err) {
			notify(err.message || 'Error adding instruments to watchlist', 'err');
			return false;
		}
	};

	/**
	 * Remove an instrument from the watchlist
	 * @param {string} tradingsymbol Trading symbol
	 * @param {('NSE'|'BSE'|'NFO'|'CDS'|'MCX')} exchange The exchange this instrument is listed under
	 * @param {string} instrument_token The instrument token shall be used to unsubscribe from live quotes
	 * @returns {Promise<boolean>} TRUE in case instruments added successfully, FALSE otherwise
	 */
	const removeInstrument = async (tradingsymbol, exchange, instrument_token) => {
		if (!tradingsymbol || typeof tradingsymbol !== 'string' || tradingsymbol.trim() === '') return false;
		if (!exchange || typeof exchange !== 'string' || exchange.trim() === '') return false;
		if (!instrument_token) return false;
		// console.log('About to remove ' + tradingsymbol + ' from Indexed DB');
		try {
			//here first delete from IndexedDB
			const deleteOpStatus = await deleteWatchlistInstrument(activeWatchlistIndex + 1, tradingsymbol, exchange);
			if (!deleteOpStatus) throw new Error('Failed to remove instrument from watchlist');

			//then remove from state
			setWatchlistInstrumentsAry(
				// watchlistInstrumentsAry.filter((instrument) => instrument.tradingsymbol !== tradingsymbol && instrument.exchange !== exchange),
				watchlistInstrumentsAry.filter((instrument) => instrument.token !== instrument_token),
			);
			//unsubscribe removed instrument from ws
			isOnline && _unsubscribeToQuotes_nonPositionTokensOnly([instrument_token]);
			return true;
		} catch (err) {
			return false;
		}
	};
	//AI example
	// const removeMultipleInstruments = (memberIdsToDelete) => {
	// 	setMembers(members.filter((member) => !memberIdsToDelete.includes(member.id)));
	// };
	// // Example usage: removeMultipleInstruments([1, 2]); to delete members with id 1 and 2

	// const editMember = (memberId, newName) => {
	// 	setMembers(members.map((member) => (member.id === memberId ? { ...member, name: newName } : member)));
	// };

	/**
	 * Remove an instrument from the the not found list
	 * @param {string} tradingsymbol Trading symbol
	 * @param {('NSE'|'BSE'|'NFO'|'CDS'|'MCX')} exchange The exchange this instrument is listed under
	 * @returns {Promise<boolean>} TRUE in case instrument removed successfully, FALSE otherwise
	 */
	const removeNotFoundInstrument = async (tradingsymbol, exchange) => {
		if (!tradingsymbol || typeof tradingsymbol !== 'string' || tradingsymbol.trim() === '') return false;
		if (!exchange || typeof exchange !== 'string' || exchange.trim() === '') return false;
		// console.log('About to remove ' + tradingsymbol + ' from Indexed DB');
		try {
			//here first delete from IndexedDB
			const deleteOpStatus = await deleteWatchlistInstrument(activeWatchlistIndex + 1, tradingsymbol, exchange);
			if (!deleteOpStatus) throw new Error('Failed to remove instrument from watchlist');

			//then remove from state
			setWatchlistInstrumentsNotFoundAry(
				// watchlistInstrumentsAry.filter((instrument) => instrument.tradingsymbol !== tradingsymbol && instrument.exchange !== exchange),
				watchlistInstrumentsNotFoundAry.filter(({ symbol, exchange: exch }) => !(symbol === tradingsymbol && exch === exchange)),
			);
			return true;
		} catch (err) {
			return false;
		}
	};

	//RUNS ON MOUNT & THEN WHENEVER 'activeWatchlistIndex' CHANGES (for eg, when switching between watchlists) or whenever master-data becomes available and ready to be read
	useEffect(() => {
		(async () => {
			// unsubscribeToQuotes(watchlistInstrumentsAry.map(({ instrument_token }) => Number(instrument_token))); //unsubscibe all quotes from outgoing list	//map is used to convert array of strings to array of numbers
			if (isMasterDataReady) await getWatchlist_n_loadIntoState_n_subscribeToWsLiveQuotes(); //this will then load instruments (and subscribe to WS) for the page specified by activeWatchlistIndex
			// setIsReady(true);
			setBottomSheetTitle(`Watchlist ${activeWatchlistIndex + 1}`);
			setBottomSheetDesc('');
		})();
	}, [activeWatchlistIndex, isMasterDataReady]);

	useEffect(() => {
		// if (Object.keys(instrumentInvokedForTransaction).length === 0) {
		// 	setBottomSheetTitle(`Watchlist ${activeWatchlistIndex + 1}`);
		// 	setBottomSheetDesc('');
		// } else {
		// 	setBottomSheetTitle(instrumentInvokedForTransaction.symbol + ' ' + instrumentInvokedForTransaction.segment);
		// 	setBottomSheetDesc(instrumentInvokedForTransaction.name);
		// }

		//toggle the bottom-sheet title when showing BUY/SELL dialog
		setBottomSheetTitle(
			Object.keys(instrumentInvokedForTransaction).length === 0 ? `Watchlist ${activeWatchlistIndex + 1}` : null, //instrumentInvokedForTransaction.symbol + ' ' + instrumentInvokedForTransaction.segment,
		);
	}, [instrumentInvokedForTransaction]);

	/* useEffect(() => {
		(async () => {
			if (isOnline && watchlistInstrumentsAry.length > 0) {
				// console.log('Watchlist: Network reconnected. Waiting 2 secs before re-subscribing to WS');
				await new Promise((resolve) => setTimeout(resolve, 2000)); //wait for 2 seconds for websocket connection to be established successfully
				// console.log('Watchlist: Subscribing to quotes');
				// await subscribeToQuotes(_segregateInstrumentTokenByExchanges(watchlistInstrumentsAry));
				await subscribeToQuotes(watchlistInstrumentsAry.map(({ token }) => token));
			}
			//foll call shall anyhow fail coz no network wud b available
			// else {
			// 	unsubscribeToQuotes(watchlistInstrumentsAry.map(({ instrument_token }) => Number(instrument_token)));;
			// }
		})();
	}, [isOnline]); //runs on mount & when 'isOnline' changes */
	const [isRetryWip, setIsRetryWip] = useState(false);

	/** @type {{current:?number}} Timer ID */
	const wsRetryTimerRef = useRef(null);

	/** Clears any retries that had been scheduled */
	const _stopRetryingFurther = () => {
		wsRetryTimerRef.current !== null && clearTimeout(wsRetryTimerRef.current);
		setTimeout(setIsRetryWip.bind(this, false), 3000);
	};

	/** Subscribes to quotes and also schedules retries if attempt fails */
	const _tryAndRetrySubcribing = async () => {
		console.log('WATCHLIST: Trying to subscribe to quotes since WS is inactive');
		setIsRetryWip(true);
		const sub = await subscribeToQuotes(watchlistInstrumentsAry.map(({ token }) => token));
		if (!sub) {
			wsRetryTimerRef.current !== null && clearTimeout(wsRetryTimerRef.current); //clear previously scheduled timers if any
			wsRetryTimerRef.current = setTimeout(_tryAndRetrySubcribing, 3000);
		} else {
			_stopRetryingFurther();
		}
	};

	/** @type {{current:?Boolean}} Whether effect has completed its first run */
	const hasAlreadyRunOnMount = useRef(false);
	useEffect(() => {
		if (isMasterDataReady) {
			if (hasAlreadyRunOnMount.current) {
				//if this is a subsequent run and not the first mount run

				if (watchlistInstrumentsAry.length && socketStatus != 2) {
					if (isOnline) {
						console.log('WATCHLIST: After coming back online or after waking up from sleep, we are resubscribing to quotes since WS is inactive');
						(async () => {
							await _tryAndRetrySubcribing();
						})();
					} else {
						console.log('WATCHLIST: Stopping retrying since offline');
						_stopRetryingFurther();
					}
				} else {
					console.log('WATCHLIST: Either no instruments exist or WS is active and responding, thus stopping from retrying');
					_stopRetryingFurther();
				}
			} else {
				//if this is first mount run
				// (async () => {
				// 	await getWatchlist_n_loadIntoState_n_subscribeToWsLiveQuotes();
				// 	// setIsReady(true); //we set this when we receive the first tick
				// })();
				//ABOVE HAS BEEN COMMENTED OUT COZ WE RUN IT IN DIFF EFFECT AFTER WATCHING WHENEVER 'activeWatchlistIndex' CHANGES

				hasAlreadyRunOnMount.current = true;
			}
		}
		// return () => {
		// 	// isOnline && positionsAry.length > 0 && unsubscribeToQuotes(_segregateInstrumentTokenByExchanges(positionsAry));
		// 	isOnline && positionsAry.length > 0 && unsubscribeToQuotes(positionsAry.map(({ instrument_token }) => instrument_token));
		// };
	}, [isOnline, socketStatus, isMasterDataReady]); //runs on mount & when 'isOnline', 'socketStatus' or 'isMasterDataReady' changes

	// let hasFirstRunOnMountFinished = false;
	/** @type {{current:boolean}} Whether first mount run has done its run */
	const hasFirstRunOnMountFinished = useRef(false);
	useEffect(() => {
		// console.log('MrktWtch useEffect() tick:', tick);
		// console.log('MrktWtch useEffect() quotes:', Object.keys(quotes));
		// console.log('MarketWatch useEffect quotes:', Object.keys(quotes));
		// note that the following wud never fire in case there are no instruments in the watchlist, since no tick wud be ever received. Thus we also set 'setIsReady(true)' when reading watchlist instruments but none are found
		hasFirstRunOnMountFinished.current && setIsReady(true); //on receiving first tick quote from WS, we hide loading overlay by setting this to true (and also sets on subsequent runs but doesnt matter)
		hasFirstRunOnMountFinished.current = true;
	}, [tick]); //}, [quotes]); //runs on mount and then when 'tick' changes

	// useEffect(() => {
	// 	//here if search query goes from '' to 'something', move into search instruments mode
	// 	//start search
	// 	if (searchQuery.trim() === '') return; //or here resubscribe to MW quotes for currently active watchlist
	// 	(async () => {
	// 		const searchRes = await searchInstruments('NSE', searchQuery, 20);
	// 		if (!searchRes) console.log('No items found');
	// 		// console.log('searchRes:', searchRes);
	// 		Array.isArray(searchRes) && setSearchResults(searchRes);
	// 	})();

	// 	// return () => {};
	// }, [searchQuery]); //runs on mount and then when 'searchQuery' changes

	// useEffect(() => {
	// 	const activeWatchListInstrumentTokenStrAry = Object.keys(activeWatchlistInstruments_metaDataObj);
	// 	if (activeWatchListInstrumentTokenStrAry.length > 0) {
	// 		mode === 'search'
	// 			? unsubscribeToQuotes(activeWatchListInstrumentTokenStrAry.map(Number))
	// 			: (async () => {
	// 					//resubscribe to quotes
	// 					await subscribeToQuotes(activeWatchListInstrumentTokenStrAry.map(Number));
	// 				})();
	// 	}
	// }, [mode]); //runs on mount and then when 'mode' changes

	// if (!isMasterDataReady) return null;
	return Object.keys(instrumentInvokedForTransaction).length === 0 ? (
		//when we have not moved into the BUY/SELL window yet, we show the watchlist/searchlist
		<div className={styles.marketWatchC}>
			<div className={styles.marketWatchHdr}>
				{/* <h2>Watchlist</h2> */}
				<TextInput
					placeholder={`Add to Watchlist-${activeWatchlistIndex + 1}`}
					icon="search"
					value={searchQuery}
					onChange={(e) => {
						setSearchQuery(e.target.value);
					}}
				/>
			</div>
			<div className={styles.marketWatchMain}>
				{searchQuery.trim() === '' ? ( //display watchlist
					<>
						<div className={styles.watchlistC}>
							{isMasterDataReady &&
								isReady &&
								(watchlistInstrumentsAry.length > 0 || watchlistInstrumentsNotFoundAry.length > 0 ? (
									<>
										{watchlistInstrumentsAry.length > 0 &&
											watchlistInstrumentsAry.map((instrument, i) => {
												const { symbol, name, token, segment: exchange } = instrument;
												const isExpanded = currentlyExpandedInstrument && currentlyExpandedInstrument.token === token;
												return (
													<WatchlistItem
														wrapperElement="div"
														key={token}
														onClick={() => {
															setCurrentlyExpandedInstrument(isExpanded ? {} : instrument);
														}}
														isExpandedView={isExpanded}
														tradingsymbol={symbol.replace(/-EQ$/i, '')} //we trim the ending '-EQ' part for NSE instruments. For eg 'INFY-EQ' --> 'INFY'
														entityName={name}
														exchange={exchange}
														segment={exchange}
														ltp={quotes?.[token]?.ltp}
														closePrice={quotes?.[token]?.cp}
														closeExpandedView={() => {
															setCurrentlyExpandedInstrument({});
														}}
														onBuyClick={() => {
															isOnline ? setInstrumentInvokedForTransaction(instrument) : notify('Network unavailable', 'err');
														}}
														onRemoveClick={() => {
															removeInstrument(symbol, exchange, token).then(() => {
																setCurrentlyExpandedInstrument({});
															});
														}}
													/>
												);
											})}
										{watchlistInstrumentsNotFoundAry.length > 0 && (
											<div className={styles.wlItmsNotFoundC}>
												<h3>Instruments not found</h3>
												{watchlistInstrumentsNotFoundAry.map(({ symbol, exchange }) => (
													<div key={`${symbol}:${exchange}`}>
														<span>{symbol}</span>
														<Button
															variant="tertiary"
															isDark={true}
															icon="trash-2"
															onClick={(e) => {
																removeNotFoundInstrument(symbol, exchange);
																// e.stopPropagation(); //prevents event on parent elm rom firing
															}}
														/>
													</div>
												))}
											</div>
										)}
									</>
								) : (
									<EmptyGfx icon="binocular" note={`Watchlist-${activeWatchlistIndex + 1} is empty`} isOverlay={true} />
								))}
						</div>

						<div className={styles.watchListFtr}>
							<div className={styles.watchlistTabsC}>
								{[1, 2, 3, 4].map((pageNum, i) => (
									<button
										key={pageNum}
										className={i === activeWatchlistIndex ? styles.active : ''}
										onClick={() => {
											setActiveWatchlistIndex(i);
										}}
									>
										{pageNum}
									</button>
								))}
							</div>
						</div>
						{!isReady && <Loading note="Loading Watchlist" />}
					</>
				) : (
					<Upstox_MarketWatch_SearchResults
						searchQuery={searchQuery}
						cancelSearch={() => {
							setSearchQuery('');
						}}
						addToWatchlist={addInstruments}
						watchlistInstrumentsAry={watchlistInstrumentsAry}
						maxNumInstrumentsPerWatchlist={maxNumInstrumentsPerWatchlist}
					/>
				)}
			</div>
			{!isOnline ? (
				<EmptyGfx
					icon="alert-circle"
					note="Network unavailable"
					// ctaFn={async () => {
					// 	await getPositions_n_loadIntoState_n_subscribeToWsLiveQuotes();
					// }}
					// ctaBtnText="Reconnect"
					isOverlay={true}
				/>
			) : (
				isMasterDataReady &&
				(!isReady ? ( //if network is available and master data is ready, but instruments are still being loaded, and waiting for first quote tick from websocket
					<Loading note="Loading Watchlist" />
				) : // 	watchlistInstrumentsAry.length < 1 ? ( //if no instruments exit
				// watchlistInstrumentsNotFoundAry.length < 1 && ( //if no not-found instruments, then show empty list gfx
				// 	<EmptyGfx icon="binocular" note={`Watchlist-${activeWatchlistIndex + 1} is empty`} isOverlay={true} />
				// )
				// 	) :
				isRetryWip ? (
					<Loading note="Reconnecting" />
				) : socketStatus === 0 ? ( //if positions exist and the socket is closed (could happen when PC comes out of sleep or mobile app gets focused from being in the background)
					// showReviveWebsocketBtn && (
					watchlistInstrumentsAry.length > 0 && (
						<EmptyGfx
							icon="alert-circle"
							note="Connection to live data interrupted"
							ctaFn={async () => {
								await getWatchlist_n_loadIntoState_n_subscribeToWsLiveQuotes();
							}}
							ctaBtnText="Reconnect"
							isOverlay={true}
						/>
					)
				) : (
					// )
					//if socket is open, but still waiting for response (for eg, when retrying)
					socketStatus === 1 && <Loading note="Fetching live quotes" />
				))
			)}
		</div>
	) : (
		(() => {
			const { token, symbol, name, segment: exchange, lotsize } = instrumentInvokedForTransaction;
			return (
				<NewTradePositionDialog
					tradingsymbol={symbol} //{exchange === 'NFO' || exchange === 'MCX' ? symbol : name}
					instrumentName={name}
					exchange={exchange}
					lotSize={lotsize}
					ltp={quotes?.[token]?.ltp}
					closePrice={quotes?.[token]?.cp}
					openNewOrAddToPosition={openNewOrAddToPosition}
					closeDialog={closeBottomSheet}
					cancelOp={() => {
						setInstrumentInvokedForTransaction({}); //brings user back to watchlist
					}}
				/>
			);
		})()
	);
}
