/** Provider component for downloaded master data.
 * We use IndexedDB to store data for offline access.
 * @see {@link https://javascript.info/indexeddb}
 * @see {@link https://web.dev/indexeddb}
 */
export default function UpstoxMasterData_ContextProvider({ children }) {
	const [isLoading, setIsLoading] = useState(false);
	const [isMasterDataReady, setIsMasterDataReady] = useState(false);
	const [masterDataEpochTimestamp, setMasterDataEpochTimestamp] = useState(null); //in child components we can watch for when this changes in order to update it's own state with current data

	// const dbRef = useRef(null); //we do not store it in a normal 'var' so as for it to persist across re-renders, kindoff like a static value

	const isOnline = useContext(NetworkCheckContext);
	const { id: kaagziUserId } = useContext(UserContext);
	const { id: upstoxUserId, accessToken } = useContext(UpstoxUserContext);

	const dbRef = useRef(null);

	const currentDbStoreVer = 1; //if there are any changes to the DB structure, we can increment this

	/** @type {['NSE', 'BSE', 'NFO', 'CDS', 'MCX']} Array of exchanges we download master data for */
	const exchangesAry = ['NSE', 'BSE', 'NFO', 'CDS', 'MCX'];

	/**
	 * Sets up & initializes IndexedDB client and saves it as static for reuse later
	 * @returns {Promise<?IDBDatabase>} IndexedDB handle or DOMException error.
	 */
	async function __setupIfNotAlreadyAndGetDbHandle() {
		return new Promise((resolve, reject) => {
			//check if a DB handle is already stored
			if (dbRef.current?.constructor.name == 'IDBDatabase') {
				if (dbRef.current?.name === 'UpstoxMasterData') {
					return resolve(dbRef.current); //if the stored DB is the one that we req, then return it
				} else {
					//close any other open DB connections (Mostly this could be of different user logged-in before the current user has just loggen-in)
					dbRef.current?.close?.(); //since anyhow we shall be only allowing one single user logged-in at any given time, and that user shall have one single DB
				}
			}

			//setup DB if not already
			const openRequest = indexedDB.open('UpstoxMasterData', currentDbStoreVer); //openRequest.construstor.name == IDBOpenDBRequest

			//EVENTS
			openRequest.onupgradeneeded = (event) => {
				//only fired when an attempt was made to open a database with a version number higher than its current version, or if no database existed before
				dbRef.current = openRequest.result; //same as 'event.target.result'	//had we not required it below to get 'dbRef.current.objectStoreNames' we need not have required to assign it here since we do it in the 'onsuccess' event

				// check existing db version
				if (event.oldVersion === 0) {
					// version 0 means that the client had no database
					// perform initialization

					// if (!dbRef.current.objectStoreNames.contains('NSE')) {
					// 	//dbRef.current.createObjectStore('instruments', { keyPath: 'id' }); // here we specify the column-name to tell what it should use as primary-key (weve named it as 'id' as short for instrumentId)
					// 	////so now, when adding or updating items, we need not specify the 'key' explicitely
					// 	dbRef.current.createObjectStore('instruments');
					// }
					// //the 'metaData' table shall be used to store any meta data related to master data, for eg, last data fetch timestamp (since this data needs to be refreshed each trading day)
					// if (!dbRef.current.objectStoreNames.contains('metaData')) {
					// 	dbRef.current.createObjectStore('metaData'); // note that in this case, we do not tell it to use inline keys from the data by opting not to specify the keyPath
					// }
					[...exchangesAry, 'metaData'].forEach((storeName) => {
						if (!dbRef.current.objectStoreNames.contains(storeName)) dbRef.current.createObjectStore(storeName);
					});
				} else if (event.oldVersion > 0 && event.oldVersion < currentDbStoreVer) {
					// client had old version
					// update
					[...exchangesAry, 'metaData'].forEach((storeName) => {
						dbRef.current.createObjectStore(storeName);
					});
				}
			};

			openRequest.onerror = () => {
				reject(openRequest.error);
			};

			openRequest.onsuccess = (event) => {
				//fired after 'onupgradeneeded()' and if no errors while opening
				dbRef.current = openRequest.result; //event.target.result;
				dbRef.current.onversionchange = () => {
					//installs the onversionchange handler, that triggers if the current database connection becomes outdated (db version is updated elsewhere) and closes the connection
					dbRef.current.close();
					dbRef.current = null;
					console.warn('Master database is outdated, please reload the page');
				};
				dbRef.current.onclose = () => {
					//fires only if the DB connection is unexpectedly closed
					dbRef.current = null; // console.log("Database connection closed");
				};
				// console.log('typeof dbRef.current:', typeof dbRef.current);					//object
				// console.log('dbRef.current.constructor.name:', dbRef.current.constructor.name);		//IDBDatabase
				// the db is ready, continue working with database using dbRef.current object

				// resolve(openRequest.result);
				resolve(dbRef.current);
			};
		});
	}

	/**
	 * Initiates a transaction after getting handle to DB
	 * @param {(string|string[])} tableOrTablesAry ObjectStore or array of ObjectStores
	 * @param {IDBTransactionMode} mode Mode of transaction
	 * @returns {Promise<?IDBTransaction>} IndexedDb Transaction
	 */
	const _withDbTransaction = async (tableOrTablesAry, mode) => {
		if (!tableOrTablesAry) return null;
		if (typeof tableOrTablesAry === 'string' && tableOrTablesAry.trim() === '') return null;
		if (!['readonly', 'readwrite', 'versionchange'].includes(mode)) return null;
		try {
			const db = await __setupIfNotAlreadyAndGetDbHandle();
			if (!db) return null;

			//check if table exists in DB
			const tables = db.objectStoreNames; //https://developer.mozilla.org/en-US/docs/Web/API/IDBDatabase/objectStoreNames
			if (tables.length < 1) return null; //since we do not have any tables configured in this DB
			const tablesAry = Array.from(tables); //since, db.objectStoreNames return DOMStringList and not Array, we convert it to array
			if (Array.isArray(tableOrTablesAry)) {
				for (var i = 0; i < tableOrTablesAry.length; i++) {
					if (!tablesAry.includes(tableOrTablesAry[i])) throw new Error('The ' + tableOrTablesAry[i] + ' table does not exist in cache database');
				}
			} else if (typeof tableOrTablesAry === 'string') {
				if (!tablesAry.includes(tableOrTablesAry)) throw new Error('The ' + tableOrTablesAry + ' table does not exist in cache database');
			}
			return db.transaction(tableOrTablesAry, mode);
		} catch (err) {
			console.error(err.message);
			return null;
		}
	};

	/** Clears all tables in the 'UpstoxMasterData' IndexedDB database
	 * @returns {Promise<boolean>} TRUE if clearing successful. FALSE otherwise.
	 */
	const _clearAllTables = async () => {
		const db = await __setupIfNotAlreadyAndGetDbHandle();
		if (!db) return false;
		return new Promise((resolve, reject) => {
			try {
				const tables = db.objectStoreNames; //https://developer.mozilla.org/en-US/docs/Web/API/IDBDatabase/objectStoreNames
				if (tables.length < 1) return resolve(true); //since we do not have any tables to clear

				const tablesAry = Array.from(tables); //since, db.objectStoreNames return DOMStringList and not Array, we convert it to array

				const transaction = db.transaction(tablesAry, 'readwrite'); //https://developer.chrome.com/blog/defining-scope-In-indexeddb-transactions/

				transaction.onabort = () => {
					reject(transaction.error);
				};
				transaction.oncomplete = () => {
					resolve(true);
				};

				tablesAry.forEach((table) => {
					// let clearRequest = transaction.objectStore(table).clear();	// clear the storage
					// clearRequest.onerror = (event) => { reject(`Error clearing '${table}' cache`); };
					// clearRequest.onsuccess = () => {resolve();};	//this may prematurely resolve promise before next ir=teration inside loop
					transaction.objectStore(table).clear();
					// console.log(`Cleared ${table} cache`);
				});
				// resolve(true);
			} catch (err) {
				reject();
			}
		});
	};

	/** Checks if master data is valid for today.
	 * If time right now is past 7:30 AM, then we check if last download time is anytime past 7:30 AM
	 * If time right now is before 7:30 AM, then we check if last download time is anytime past 7:30 AM of yesterday.
	 * As per Upstox, their master data refresehes each day around 6 AM.
	 * @returns {Promise<(number|false)>}  If data is valid for the time, epoch timestamp for when the stored data was fetched, FALSE otherwise
	 * @see {@link https://upstox.com/developer/api-documentation/instruments/}
	 */
	const _checkIfMasterDataValidForToday = async () => {
		try {
			// const db = await __setupIfNotAlreadyAndGetDbHandle();
			// if (!db) return false;

			// //check if table exists in DB
			// const tables = db.objectStoreNames; //https://developer.mozilla.org/en-US/docs/Web/API/IDBDatabase/objectStoreNames
			// if (tables.length < 1) return false; //reject(); //since we do not have any tables configured in this DB
			// const tablesAry = Array.from(tables); //since, db.objectStoreNames return DOMStringList and not Array, we convert it to array
			// if (!tablesAry.includes('metaData')) throw new Error("Master data reading failed! The 'metaData' table does not exist in cache database"); //reject(`Write failed! The 'metaData' table does not exist in database`);

			// const transaction = db.transaction('metaData', 'readonly');
			const transaction = await _withDbTransaction('metaData', 'readonly');

			const request = transaction.objectStore('metaData').get('masterData_dl_timestamp');
			const lastDlEpoch = await new Promise((resolve, reject) => {
				request.onerror = () => reject(request.error);
				request.onsuccess = () => {
					if (request.result !== undefined) {
						resolve(request.result);
					} else reject(false);
				};
			});
			if (!lastDlEpoch) return false;

			//here check epoch
			//Chat GPT prompt:
			//write a javascript function that accepts a epoch in ms and returns a boolean given the following condition:
			//If current time is more than 7:30 AM, today, the function checks if the argument epoch is not less than today 7:30 am. If it is less than today 7:30 am, then returns FALSE, else returns TRUE.
			//If the current time is less than 7:30 AM, today, the function checks if the argument epoch is not less than yesterday 7:30 am. If it is less than yesterday 7:30 am, then returns false, else returns true
			// Get the current time
			const now = new Date();

			// Create a date object for today at 7:30 AM
			const today730AM = new Date();
			today730AM.setHours(7, 30, 0, 0);

			// Create a date object for yesterday at 7:30 AM
			const yesterday730AM = new Date(today730AM);
			yesterday730AM.setDate(yesterday730AM.getDate() - 1);

			// Convert the epoch time to a date object
			const lastDlEpochDate = new Date(lastDlEpoch);

			// Check the current time and compare with the epoch time
			if (now >= today730AM) {
				// If current time is more than 7:30 AM today
				// return lastDlEpochDate >= today730AM;
				return lastDlEpochDate >= today730AM ? Number(lastDlEpoch) : false;
			} else {
				// If current time is less than 7:30 AM today
				// return lastDlEpochDate >= yesterday730AM;
				return lastDlEpochDate >= yesterday730AM ? Number(lastDlEpoch) : false;
			}
		} catch (err) {
			return false;
		}
	};

	/** Fetches master data and updates IndexedDB.
	 * The tradingsymbol is used as the key and the data is stored as CSV row value.
	 * @returns {Promise<?Date>} Returns date object for when this data is being fetched
	 */
	const _fetchMasterDataAndUpdateInDb = async () => {
		if (isLoading) return false;
		try {
			setIsLoading(true);
			// browser.runtime.sendMessage({ action: 'upstoxMasterData_isDownloading' });
			// if (!isOnline) return false;
			//here we can first do some checks for if data already exists

			// const response = await fetch('https://margincalculator.angelbroking.com/OpenAPI_File/files/OpenAPIScripMaster.json');
			// const masterDataAry = await response.json();
			// if (!masterDataAry) throw new Error('Error fetching AngelOne master data');

			/** @type {{tradingsymbol,segment,csvRowData}[][]} An array of arrays, each containing parsed data*/
			const fetchRespAry = await Promise.all(
				// exchangesAry.map(async (exchange) => {
				['NSE', 'BSE', 'MCX'].map(async (exchange) => {
					//NFO is listed in same data as NSE and maybe CDS is listed in same data as BSE
					const response = await fetch(`https://nimworks.github.io/market-data/upstox/${exchange}.csv.gz`, {
						method: 'GET',
						headers: {
							// Accept: 'application/gzip',
							'Accept-Encoding': 'gzip',
						},
					});
					const blobObj = await response.blob();
					/////
					//https://stackoverflow.com/questions/36185110/is-there-a-way-to-use-browsers-native-gzip-decompression-using-javascript
					//https://developer.chrome.com/blog/compression-streams-api
					//https://developer.mozilla.org/en-US/docs/Web/API/Compression_Streams_API
					const ds = new DecompressionStream('gzip');
					const decompressedStream = blobObj.stream().pipeThrough(ds);
					const csvTxtData = await new Response(decompressedStream).text();
					// Parse the CSV string
					const rows = csvTxtData.trim().split('\n');
					rows.shift(); //remove the header row
					//return an array
					return rows.map((row) => {
						const columns = row.split(',');
						return {
							tradingsymbol: columns[1], // Assuming 'tradingsymbol' is the 2nd column
							segment: columns[0].split('|')[0], // Infer 'segment' from the instrument_key which shall be of the format 'segment|isin'
							csvRowData: row,
						};
					});
				}),
			);
			if (!fetchRespAry) throw new Error('Error fetching Upstox master data');

			//here clear all tables
			await _clearAllTables();
			setIsMasterDataReady(false);

			const transaction = await _withDbTransaction([...exchangesAry, 'metaData'], 'readwrite');
			const nseTable = transaction.objectStore('NSE'),
				bseTable = transaction.objectStore('BSE'),
				nfoTable = transaction.objectStore('NFO'),
				cdsTable = transaction.objectStore('CDS'),
				mcxTable = transaction.objectStore('MCX');
			// console.log('masterDataAry', masterDataAry.length);

			fetchRespAry.forEach((itemsAry, index) => {
				// const table = transaction.objectStore(exchangesAry[index]);
				// itemsAry.forEach((item) => {
				// 	table.put(item.data, item.tradingsymbol);
				// });
				itemsAry.forEach((item) => {
					const { tradingsymbol, segment, csvRowData } = item;
					//for NSE instruments, only save the 'EQ' ie equity type instruments and ignore other like BL
					if (segment === 'NSE_EQ') nseTable.put(`${csvRowData},NSE`, tradingsymbol);
					if (segment === 'BSE_EQ') bseTable.put(`${csvRowData},BSE`, tradingsymbol);
					if (segment === 'NSE_FO') nfoTable.put(`${csvRowData},NFO`, tradingsymbol);
					// if (segment === 'BSE_FO') nfoTable.put(`${csvRowData},NFO`, tradingsymbol);
					if (segment === 'NCD_FO') cdsTable.put(`${csvRowData},CDS`, tradingsymbol);
					// if (segment === 'BCD_FO') cdsTable.put(`${csvRowData},CDS`, tradingsymbol);
					if (segment === 'MCX_FO') mcxTable.put(`${csvRowData},MCX`, tradingsymbol);
				});
			});

			const metaDataTable = transaction.objectStore('metaData');

			const epochTimestamp = Date.now();
			metaDataTable.put(epochTimestamp, 'masterData_dl_timestamp');

			setIsMasterDataReady(true);
			setMasterDataEpochTimestamp(epochTimestamp);
			setIsLoading(false);

			return new Promise((resolve, reject) => {
				transaction.onabort = () => reject(transaction.error);
				transaction.oncomplete = () => resolve(true);
			});
		} catch (err) {
			console.error(err.message);
			setIsLoading(false);
			return false;
		}
	};

	/**
	 * Checks if data exists or is valid for today and refetches if necessary
	 * @returns {Promise<Boolean>} TRUE if valid and loaded, FALSE in case of any error
	 */
	const _checkValidityAndReFetchIfNecessary = async () => {
		try {
			const lastDownloadEpoch = await _checkIfMasterDataValidForToday(); //here check IndexedDB 'metaData' table to know when the master data was last downloaded
			if (!lastDownloadEpoch) {
				//if data either does not exist or is old
				if (isLoading) return false;
				console.log('MASTER DATA: Loading');
				// setIsLoading(true);
				// isDownloading = true;
				await _fetchMasterDataAndUpdateInDb(); //if master data was not downloaded before or is from any day before today, we clear the tables and redownload master data and update meta data
				//.finally(() => {
				// 	// setIsLoading(false);
				// 	isDownloading = false;
				// });
			} else {
				console.log('MASTER DATA: Already loaded and valid');
				setIsMasterDataReady(true);
			}
			return true;
		} catch (err) {
			return false;
		}
	};

	/**
	 * Parses the CSV data stored in IndexedDb into JSON object
	 * @param {string} csvLine CSV string
	 * @returns {?UpstoxInstrument_selective}
	 */
	const _upstoxInstrumentData_csvToObj = (csvLine) => {
		try {
			const data = csvLine.split(',');
			if (data.length !== 7) return null;
			return {
				token: data[0],
				symbol: data[1],
				name: data[2],
				expiry: data[3],
				lotsize: data[4],
				instrumenttype: data[5],
				segment: data[6],
			};
		} catch (err) {
			console.error(err.message);
		}
	};

	//------------------------------+
	//		EXPORTED METHODS		|
	//------------------------------+

	/**
	 * Read an instrument stored in IndexedDb Upstox Master Data
	 * @param {('NSE'|'BSE'|'NFO'|'CDS'|'MCX')} exchange The exchange the instrument belongs to
	 * @param {string} tradingsymbol Trading symbol (Primary Key ID used in the table)
	 * @returns {Promise<?UpstoxInstrument_selective>} Instrument object or NULL
	 */
	const getInstrument = async (exchange, tradingsymbol) => {
		// if (!isReady) return null;
		if (!tradingsymbol || typeof tradingsymbol !== 'string') return null;
		if (tradingsymbol.trim() === '') return null;
		try {
			const chkValidityAndRefetchIfReqSts = await _checkValidityAndReFetchIfNecessary();
			if (!chkValidityAndRefetchIfReqSts) return null;

			const transaction = await _withDbTransaction(exchange, 'readonly');
			if (!transaction) return null;
			const request = transaction.objectStore(exchange).get(tradingsymbol);
			return new Promise((resolve, reject) => {
				request.onerror = () => reject(request.error);
				request.onsuccess = () => {
					if (request.result !== undefined) {
						//here we parse the CSV into object data
						// resolve(request.result);
						const instrumentObjFromCsv = _upstoxInstrumentData_csvToObj(request.result);
						if (!instrumentObjFromCsv) reject(null);
						resolve(instrumentObjFromCsv);
					} else reject(null);
				};
			});
		} catch (err) {
			return null;
		}
	};

	/**
	 * For each exchange, given an array of Instrument tradingsymbol (IndexedDb Key), returns array of instrument objs stored in IndexedDb Kite Master Data
	 * @param {{'exchange_name':string[]}} exchangeSymbolsObj Object with keys as the exchange name and each key has value as array of 'tradingsymbol' (primary Key ID)
	 * @returns {Promise<?{instrumentsFound:UpstoxInstrument_selective[],instrumentsNotFound:{symbol:string,exchange:('NSE'|'BSE'|'NFO'|'MCX'|'CDS')}[]}>} Instruments that were found from across all requested exchanges
	 */
	const getInstruments = async (exchangeSymbolsObj) => {
		// if (!isReady) return null;
		if (!exchangeSymbolsObj) return null;
		if (typeof exchangeSymbolsObj !== 'object') return null;
		const reqExchangesAry = Object.keys(exchangeSymbolsObj);
		if (reqExchangesAry.length < 1) return null;
		try {
			const chkValidityAndRefetchIfReqSts = await _checkValidityAndReFetchIfNecessary();
			if (!chkValidityAndRefetchIfReqSts) return null;

			const transaction = await _withDbTransaction(reqExchangesAry, 'readonly'); //since objectstores are named after the exchanges itself
			if (!transaction) return null;

			const instrumentsFound = []; //instruments found in table
			const instrumentsNotFound = []; //instruments not found in table

			/** @type {true[]} */
			const allTablesReadRespAry = await Promise.all(
				//array of promises for each table (ie exchange)
				reqExchangesAry.map(async (exchange) => {
					//the exchange name is the table name in our IndexedDB
					if (!exchangesAry.includes(exchange)) return false; //read from the exchange tables for eg NSE, BSE, NFO..
					const table = transaction.objectStore(exchange);

					//array of promises for the specified 'symbols' to get instrument data for, within the 'exchange'
					const allItemsReadAry = await Promise.all(
						exchangeSymbolsObj[exchange].map((tradingSymbol_PK) => {
							return new Promise((resolve, reject) => {
								const request = table.get(tradingSymbol_PK);
								request.onsuccess = () => {
									// console.log('request.result for ' + tradingSymbol_PK + ' :', request.result);
									if (!request.result) {
										instrumentsNotFound.push({ symbol: tradingSymbol_PK, exchange });
									} else {
										const instrumentObjFromCsv = _upstoxInstrumentData_csvToObj(request.result);
										// if (!instrumentObjFromCsv) reject(null);
										instrumentsFound.push(instrumentObjFromCsv);
									}
									resolve();
								};
								request.onerror = () => {
									instrumentsNotFound.push({ symbol: tradingSymbol_PK, exchange });
									// reject('Error retrieving instrument with key: ' + key);
									resolve();
								};
							});
						}),
					);
					return true; // return { instrumentsFound, instrumentsNotFound };
				}),
			);
			// console.log({ instrumentsFound, instrumentsNotFound });
			return new Promise((resolve, reject) => {
				transaction.onabort = () => reject(transaction.error);
				transaction.oncomplete = () => resolve({ instrumentsFound, instrumentsNotFound });
			});
		} catch (err) {
			// console.error(err);
			return null;
		}
	};

	/**
	 * For each exchange, given an array of Instrument tradingsymbol (IndexedDb Key), returns an obj with 'tradingsymbol:exchange' as property and instrument_token as value
	 * @param {{'exchange_name':string[]}} exchangeSymbolsObj Object with keys as the exchange name and each key has value as array of 'tradingsymbol' (primary Key ID)
	 * @returns {Promise<?{instrumentsAndTheirToken:{'tradingsymbol1:exchange':'instrument_token','tradingsymbol2:exchange':'instrument_token'},instrumentsNotFound:{symbol:string,exchange:('NSE'|'BSE'|'NFO'|'MCX'|'CDS')}[]}}>} Instrument tokens for each of the instruments given by tradingsymbol and exchange
	 */
	const getTokenForInstruments = async (exchangeSymbolsObj) => {
		// if (!isReady) return null;
		if (!exchangeSymbolsObj) return null;
		if (typeof exchangeSymbolsObj !== 'object') return null;
		const reqExchangesAry = Object.keys(exchangeSymbolsObj);
		if (reqExchangesAry.length < 1) return null;
		try {
			const chkValidityAndRefetchIfReqSts = await _checkValidityAndReFetchIfNecessary();
			if (!chkValidityAndRefetchIfReqSts) return null;

			const transaction = await _withDbTransaction(reqExchangesAry, 'readonly'); //since objectstores are named after the exchanges itself
			if (!transaction) return null;

			const instrumentsAndTheirToken = {}; //tokens for each instrument found in that exchange (ie table)
			const instrumentsNotFound = []; //instruments not found in table

			/** @type {true[]} */
			const allTablesReadRespAry = await Promise.all(
				//array of promises for each table (ie exchange)
				reqExchangesAry.map(async (exchange) => {
					//the exchange name is the table name in our IndexedDB
					if (!exchangesAry.includes(exchange)) return false; //read from the exchange tables for eg NSE, BSE, NFO..
					const table = transaction.objectStore(exchange);

					//array of promises for the specified 'symbols' to get instrument data for, within the 'exchange'
					const allItemsReadAry = await Promise.all(
						exchangeSymbolsObj[exchange].map((tradingSymbol_PK) => {
							return new Promise((resolve, reject) => {
								const request = table.get(tradingSymbol_PK);
								request.onsuccess = () => {
									if (request.result !== undefined) {
										const { symbol, segment, token } = _upstoxInstrumentData_csvToObj(request.result);
										// if (!instrumentObjFromCsv) reject(null);
										// instrumentsFound.push(instrumentObjFromCsv);
										instrumentsAndTheirToken[`${symbol}:${segment}`] = token;
										// resolve();
									} else {
										instrumentsNotFound.push({ symbol: tradingSymbol_PK, exchange });
									}
									resolve();
								};
								request.onerror = () => {
									// instrumentsNotFound.push(`${tradingSymbol_PK}:${exchange}`);
									// // reject('Error retrieving instrument with key: ' + key);
									reject();
								};
							});
						}),
					);
					return true; // return { instrumentsFound, instrumentsNotFound };
				}),
			);

			return new Promise((resolve, reject) => {
				transaction.onabort = () => reject(transaction.error);
				// transaction.oncomplete = () => resolve(instrumentsAndTheirToken);
				transaction.oncomplete = () => resolve({ instrumentsAndTheirToken, instrumentsNotFound });
			});
		} catch (err) {
			return null;
		}
	};

	/**
	 * Query search instruments from master data
	 * @param {Exchanges} exchange The exchange within which to search for the instrument
	 * @param {string} queryPrefix
	 * @param {?Number} [limit=20]
	 * @returns {Promise<?UpstoxInstrument_selective[]>}
	 */
	const searchInstruments = async (exchange, queryPrefix, limit) => {
		// if (!isReady) return null; //if data isn't downloaded yet
		if (queryPrefix.trim() === '') return null;
		queryPrefix = queryPrefix.toUpperCase();
		if (!limit || !Number.isInteger(Number(limit))) limit = 20;
		// console.log('searchInstruments():', 'Begin search');
		try {
			const chkValidityAndRefetchIfReqSts = await _checkValidityAndReFetchIfNecessary();
			if (!chkValidityAndRefetchIfReqSts) return null;
			// console.log('searchInstruments():', 'abt to open transaction');
			// const db = await __setupIfNotAlreadyAndGetDbHandle();
			// if (!db) return null;

			// //check if table exists in DB
			// const tables = db.objectStoreNames; //https://developer.mozilla.org/en-US/docs/Web/API/IDBDatabase/objectStoreNames
			// if (tables.length < 1) return false; //reject(); //since we do not have any tables configured in this DB
			// const tablesAry = Array.from(tables); //since, db.objectStoreNames return DOMStringList and not Array, we convert it to array
			// if (!tablesAry.includes('instruments')) throw new Error("Master data reading failed! The 'instruments' table does not exist in cache database"); //reject(`Write failed! The 'metaData' table does not exist in database`);

			// const transaction = db.transaction('instruments', 'readonly');
			const transaction = await _withDbTransaction(exchange, 'readonly');

			return await new Promise((resolve, reject) => {
				try {
					// const store = transaction.objectStore('instruments');
					// const keyRange = IDBKeyRange.bound(queryPrefix, queryPrefix + '\uffff');
					// const cursorRequest = store.openCursor(keyRange);
					const cursorRequest = transaction.objectStore(exchange).openCursor(IDBKeyRange.bound(queryPrefix, queryPrefix + '\uffff'));
					// const cursorRequest = transaction.objectStore('instruments').openCursor(IDBKeyRange.bound(queryPrefix, queryPrefix + 'z'));
					const instruments = [];
					let count = 0; // Counter for the number of collected entries

					cursorRequest.onsuccess = (e) => {
						// console.log('cursorRequest.onsuccess = (e):', e);
						const cursor = e.target.result;
						// console.log('cursor', cursor);
						if (cursor && count < limit) {
							if (cursor.key.startsWith(queryPrefix)) {
								// instruments.push(cursor.value);
								const instrumentObjFromCsv = _upstoxInstrumentData_csvToObj(cursor.value);
								instrumentObjFromCsv && instruments.push(instrumentObjFromCsv);
								// console.log('cursor.value:', cursor.value);
								count++; // Increment the counter
							}
							cursor.continue(); //continue to next item
						} else {
							// No more matching records or limit reached
							resolve(instruments);
							// console.log(instruments);
						}
					};

					// transaction.oncomplete = () => {
					// 	resolve(instruments);
					// 	console.log(instruments);
					// };

					cursorRequest.onerror = (e) => {
						reject(e);
					};
				} catch (err) {
					reject(err.message);
				}
			});
		} catch (err) {
			return null;
		}
	};

	//==========================+
	//							|
	//		EFFECT-HOOKS		|
	//							|
	//==========================+

	useEffect(() => {
		if (!isOnline) return;
		if (!kaagziUserId && !upstoxUserId) return; //proceed to chk and download master-data only if user is logged into both, Kaagzi and Zerodha Kite
		(async () => {
			await _checkValidityAndReFetchIfNecessary();
		})();
	}, [isOnline, kaagziUserId, upstoxUserId]); //runs on first mount and then when either isOnline, kaagziUserId or kiteUserId changes

	return (
		<UpstoxMasterDataContext.Provider
			value={{
				isMasterDataReady,
				masterDataEpochTimestamp,
				// getInstrumentTokensForTradingInstruments,
				getInstrument,
				getInstruments,
				getTokenForInstruments,
				searchInstruments,
			}}
		>
			{children}
			{/* {isLoading && <Loading note="Setting Up! May take time" coverFullPage={true} />} */}
			{isLoading && <Loading note="Connecting to market" coverFullPage={true} />}
		</UpstoxMasterDataContext.Provider>
	);
}
